parameters.value:
={{ 
`SELECT * FROM Estimate 
WHERE TxnDate >= '${$json.startDate}' 
AND TxnDate <= '${$json.endDate}' 
STARTPOSITION 1 MAXRESULTS 1000`
}}

parameters.jsCode:
// Get current date in Dubai timezone (UTC+4)
const now = new Date();

// Convert to Dubai time manually
const dubaiOffset = 4 * 60; // minutes
const localOffset = now.getTimezoneOffset();
const dubaiTime = new Date(now.getTime() + (dubaiOffset + localOffset) * 60000);

// Format function YYYY-MM-DD
function formatDate(date) {
  return date.toISOString().split('T')[0];
}

// End date = today (Dubai)
const endDate = new Date(dubaiTime);

// Start date = 1 month ago
const startDate = new Date(dubaiTime);
startDate.setMonth(startDate.getMonth() - 1);

return [
  {
    json: {
      startDate: formatDate(startDate),
      endDate: formatDate(endDate)
    }
  }
];

return $input.all().map(item => ({
  DocID: item.json.DocID
}));

const output = [];

for (const item of $input.all()) {
  const estimates = item.json.QueryResponse?.Estimate || [];

  for (const est of estimates) {
    output.push({
      json: {
        EstimateId: est.Id
      }
    });
  }
}

return output;

const items = $input.all();

// Collect all DocIDs
const docIds = items
  .filter(i => i.json.DocID)
  .map(i => Number(i.json.DocID));

// Output only EstimateIds that DO NOT match DocIDs
const result = items
  .filter(i => i.json.EstimateId)
  .filter(i => {
    const estimate = Number(i.json.EstimateId);

    // if DocID exists and matches → skip
    if (!isNaN(estimate) && docIds.includes(estimate)) {
      return false;
    }

    // otherwise include
    return true;
  })
  .map(i => ({
    json: {
      EstimateId: i.json.EstimateId
    }
  }));

return result;

